import type { LedgerEntryDto } from '../services/kt/models';

/** localStorage key — "Tôi đã hiểu" trên hint menu dòng báo cáo (theo `testIdPrefix`). */
export function reportGridRowHintDismissStorageKey(testIdPrefix: string): string {
  return `${testIdPrefix}-row-menu-hint-understood`;
}

/** Hint copy on row click — parity `getSharedCatalogEditBlockedMessage` / `getRowEditBlockedMessage`. */
export function getReportGridRowMenuHintMessage(message: string) {
  return (_row: LedgerEntryDto): string | undefined => message;
}

export { isRowEditHintDismissed } from './erpListRowEditHintDismiss';
