import { openWorkspaceTab } from './openWorkspaceTab';

export type OpenReportDetailViewInput = {
  /** BE SSOT — relative path + query (`/kt/so-chi-tiet?month=…`). */
  detailViewUrl: string;
  detailReportTitle: string;
  returnPath: string;
  returnTitle?: string;
  navigate: (path: string) => void;
};

/** Open report detail from BE `detailViewUrl` — parity CT `openWorkspaceTab` (Step 5a). */
export function openReportDetailView(input: OpenReportDetailViewInput): void {
  const { detailViewUrl, detailReportTitle, returnPath, returnTitle, navigate } = input;
  if (!detailViewUrl.trim()) return;

  openWorkspaceTab(
    {
      path: detailViewUrl,
      title: detailReportTitle,
      returnPath,
      returnTitle,
    },
    navigate,
  );
}

/** Row fields populated by BE for report → report drill. */
export type ReportRowDetailViewFields = {
  detailViewUrl?: string | null;
  canOpenDetailView?: boolean;
};

export function canOpenReportDetailRow(row: ReportRowDetailViewFields | null | undefined): boolean {
  return Boolean(row?.canOpenDetailView && row.detailViewUrl?.trim());
}
